@startuml
actor "Platform" as Platform1 #lightblue {
  participant CPO1 #lavender 
}

participant HUB #lavender 

actor "Platform" as Platform2 #lightblue {
  participant MSP1 #lavender 
}


CPO1 ->>HUB : HTTP: GET\nTO: MSP1 \nFROM: CPO1  
activate CPO1   
note right of HUB   :HTTP: GET\n TO: MSP1 \n FROM: CPO1    
end note  

MSP1 <- -HUB    :HTTP: RESPONSE\nto:CPO1 from:MSP1     
deactivate MSPl    

return ' This line creates an arrow going back to left side message sender automatically . It also deactivates receiver lifeline if needed.'  


@enduml
